import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Base quote tests - simple cases
  it.todo("should quote a single sword for a new customer (base + first-insurance + fee)");
  it.todo("should quote a single amulet for a new customer");
  it.todo("should quote a single staff for a new customer");
  it.todo("should quote a single potion for a new customer");
  it.todo("should quote a single component (rune) for a new customer");

  // Components special pricing
  it.todo("should quote three alike components using the building block base premium of 60 G");

  // Modifiers
  it.todo("should add 50% surcharge for cursed items");
  it.todo("should add 30% surcharge for highly enchanted items (enchantment >= 5)");
  it.todo("should apply 20% loyalty discount for customers with >= 2 years");
  it.todo("should apply 15% discount on contracts after the first");

  // Rounding in MHPCO favor
  it.todo("should round premium up to whole G (in MHPCO's favor)");

  // Claim tests
  it.todo("should reimburse claim damage minus 100 G deductible");
  it.todo("should reimburse 50% of damage for items with enchantment >= 8");
  it.todo("should fully reimburse damage for items made of dragon material");
  it.todo("should cap total payout at twice the insurance sum");
});

