const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results: Result[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const base = step.items.reduce(
        (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
        0,
      );
      const withFirstInsurance = base * 1.1;
      const premium = Math.ceil(withFirstInsurance + 5);
      return { premium };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

