const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const FIRST_INSURANCE_SURCHARGE = 0.1;
const PROCESSING_FEE = 5;

// Round in MHPCO's favor (always up) without floating-point artifacts.
const roundUp = (value: number): number => Math.ceil(value - 1e-9);

const baseFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const computePremium = (items: Item[]): number => {
  const base = items.reduce((sum, item) => sum + baseFor(item), 0);
  const withSurcharge = base * (1 + FIRST_INSURANCE_SURCHARGE);
  return roundUp(withSurcharge) + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results: Result[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      return { premium: computePremium(step.items) };
    }
    return { payout: 0, remainingCap: 0 };
  });
  return { results };
};

