type PolicyState = {
  insuranceSum: number;
  remainingCap: number;
};

const insuranceSumFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);

const processClaim = (
  policy: PolicyState,
  incident: ClaimStep["incident"],
): { payout: number; remainingCap: number } => {
  const damageTotal = incident.damages.reduce((sum, d) => sum + d.amount, 0);
  const afterDeductible = Math.max(0, damageTotal - DEDUCTIBLE);
  const payout = Math.min(afterDeductible, policy.remainingCap);
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  let quoteCount = 0;
  const policies: Record<number, PolicyState> = {};
  const results: Result[] = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      const isFirst = quoteCount === 0;
      quoteCount += 1;
      const insuranceSum = insuranceSumFor(step.items);
      policies[index] = {
        insuranceSum,
        remainingCap: CAP_MULTIPLIER * insuranceSum,
      };
      return { premium: computePremium(step.items, scenario.customer, isFirst) };
    }
    const policy = policies[step.policy];
    return processClaim(policy, step.incident);
  });
  return { results };
};

